+/// Strip single-line (`//`) and block (`/* ... */`) JS comments from a line,
+/// respecting string literals (double/single/backtick).
+///
+/// `in_block_comment` carries block-comment state across lines.
+fn strip_js_comments(line: &str, in_block_comment: &mut bool) -> String {
+    let mut result = String::with_capacity(line.len());
+    let mut chars = line.chars().peekable();
+    let mut in_single_quote = false;
+    let mut in_double_quote = false;
+    let mut in_template = false;
+    let mut escaped = false;
+
+    while let Some(ch) = chars.next() {
+        if *in_block_comment {
+            if ch == '*' && matches!(chars.peek(), Some('/')) {
+                chars.next();
+                *in_block_comment = false;
+            }
+            continue;
+        }
+
+        if escaped {
+            result.push(ch);
+            escaped = false;
+            continue;
+        }
+
+        if ch == '\\' && (in_single_quote || in_double_quote || in_template) {
+            result.push(ch);
+            escaped = true;
+            continue;
+        }
+
+        if in_single_quote {
+            if ch == '\'' {
+                in_single_quote = false;
+            }
+            result.push(ch);
+            continue;
+        }
+
+        if in_double_quote {
+            if ch == '"' {
+                in_double_quote = false;
+            }
+            result.push(ch);
+            continue;
+        }
+
+        if in_template {
+            if ch == '`' {
+                in_template = false;
+            }
+            result.push(ch);
+            continue;
+        }
+
+        match ch {
+            '/' if matches!(chars.peek(), Some('/')) => break,
+            '/' if matches!(chars.peek(), Some('*')) => {
+                chars.next();
+                *in_block_comment = true;
+            }
+            '\'' => {
+                in_single_quote = true;
+                result.push(ch);
+            }
+            '"' => {
+                in_double_quote = true;
+                result.push(ch);
+            }
+            '`' => {
+                in_template = true;
+                result.push(ch);
+            }
+            _ => result.push(ch),
+        }
+    }
+
+    result
+}
